mapper.update:
/* OutboundOrderCloseMapper.xml - updateOutboundHeaderInterfaceSendPrcs - 출고마감 인터페이스 자동송신 대상 출고마감송신결과코드 '10'(진행중) 으로 변경 */
UPDATE TWORK_INFO_OB_HD
   SET OBDDLNSNDRSLTCD = '10'
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP, 'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = 'BATCH'
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY IN

	#{item.obhdkey}

/* OutboundOrderCloseMapper.xml - updateOutboundHeaderIfSendResultCd - 출고헤더 인터페이스 송신결과 저장 */
UPDATE TWORK_INFO_OB_HD
   SET OBDDLNSNDRSLTCD = #{obddlnsndrsltcd}
	 , OBDDLNSNDRSLTMSG = #{obddlnsndrsltmsg}
	 , UPDATEDATE = #{sysdate}
	 , UPDATEURKEY = #{surkey}
 WHERE CTKEY = #{ctkey}
   AND OWKEY = #{owkey}
   AND OBHDKEY = #{obhdkey}
